def composition(layoutA, layoutB):
    """Return the layout equivalent to applying layoutB, then layoutA."""
    # Case: layoutB is None
    if layoutB is None:
        return layoutA

    # Case: layoutB is an integer
    if is_int(layoutB):
        layoutB = Layout(layoutB)

    # Case: layoutB is a tuple (compose each mode of A with matching entry of B)
    if is_tuple(layoutB):
        assert len(layoutA) == len(layoutB), f"layoutA length {len(layoutA)} != layoutB length {len(layoutB)}"
        results = []
        for i in range(len(layoutB)):
            if layoutB[i] is None:
                results.append(layoutA[i])
            else:
                results.append(composition(layoutA[i], layoutB[i]))
        return make_layout(results)

    # From here, layoutB is a Layout
    assert is_layout(layoutB), f"layoutB must be Layout, tuple, int, or None, got {type(layoutB)}"

    # Case: layoutB has stride zero
    if is_tuple(layoutB.stride):
        if all(s == 0 for s in flatten(layoutB.stride)):
            return Layout(layoutB.shape)
    elif layoutB.stride == 0:
        return Layout(layoutB.shape)

    # Case: layoutA has hierarchical shape
    if is_tuple(layoutA.shape):
        results = []
        for i in range(len(layoutA)):
            results.append(composition(layoutA[i], layoutB))
        return make_layout(results)

    # Case: general rank-1 layoutB (scalar shape)
    # Use coalesced modes of layoutA to compute composed shape and stride
    assert is_int(layoutA.shape), f"layoutA.shape must be int at this point, got {layoutA.shape}"

    # Coalesce layoutB
    B_coal = coalesce(layoutB)

    # Build the composition by mapping each coalesced mode of B through A
    comp_shape = []
    comp_stride = []

    for b_shape, b_stride in zip(flatten(B_coal.shape), flatten(B_coal.stride)):
        comp_shape.append(b_shape)
        comp_stride.append(layoutA.stride * b_stride)

    if len(comp_shape) == 1:
        return Layout(comp_shape[0], comp_stride[0])
    return Layout(tuple(comp_shape), tuple(comp_stride))

