    if layoutB is None:
        return layoutA

    # Case: layoutB is an integer
    if is_int(layoutB):
        layoutB = Layout(layoutB)

    # Case: layoutB is a tuple (compose each mode of A with matching entry of B)
    if is_tuple(layoutB):
        assert len(layoutA) == len(layoutB), f"layoutA length {len(layoutA)} != layoutB length {len(layoutB)}"
        results = []
        for i in range(len(layoutB)):
            if layoutB[i] is None:
                results.append(layoutA[i])
            else:
                results.append(composition(layoutA[i], layoutB[i]))
        return make_layout(results)

    # From here, layoutB is a Layout
    assert is_layout(layoutB), f"layoutB must be Layout, tuple, int, or None, got {type(layoutB)}"

    # Case: layoutB has stride zero (all strides are 0)
    if is_tuple(layoutB.stride):
        if all(s == 0 for s in flatten(layoutB.stride)):
            # Create matching stride structure with all zeros
            def make_zero_stride(shape):
                if is_tuple(shape):
                    return tuple(make_zero_stride(s) for s in shape)
                return 0
            return Layout(layoutB.shape, make_zero_stride(layoutB.shape))
    elif layoutB.stride == 0:
        return Layout(layoutB.shape, 0)

    # Case: layoutB has hierarchical shape
    if is_tuple(layoutB.shape):
        results = []
        for i in range(len(layoutB)):
            results.append(composition(layoutA, layoutB[i]))
        return make_layout(results)

    # Case: general rank-1 layouts (both scalar shape, or A is coalesced to scalar)
    # Coalesce both layoutA and layoutB
    A_coal = coalesce(layoutA) if is_tuple(layoutA.shape) else layoutA
    B_coal = coalesce(layoutB) if is_tuple(layoutB.shape) else layoutB

    # Build the composition by mapping each coalesced mode of B through A
    comp_shape = []
    comp_stride = []

    for b_shape, b_stride in zip(flatten(B_coal.shape), flatten(B_coal.stride)):
        comp_shape.append(b_shape)
        comp_stride.append(A_coal.stride * b_stride)

    if len(comp_shape) == 1:
        result = Layout(comp_shape[0], comp_stride[0])
    else:
        result = Layout(tuple(comp_shape), tuple(comp_stride))

    # Coalesce the result to simplify
    return coalesce(result)
